return resultado;

const items = $input.all().map(item => item.json);

// El de arriba: ya viene formateado
const formateado = items.find(i => !i.result && i.nombre !== undefined) ?? {};

// El de abajo: respuesta cruda de Odoo
const raw = items.find(i => Array.isArray(i.result)) ?? {};
const rawRow = raw.result?.[0] ?? {};

// País del de abajo, si existe
const paisAbajoId = Array.isArray(rawRow.country_id)
  ? rawRow.country_id[0]
  : null;

const paisAbajoNombre = Array.isArray(rawRow.country_id)
  ? rawRow.country_id[1]
  : "";

// País final:
// 1) usa el de abajo si tiene
// 2) sino usa el de arriba
// 3) sino queda vacío/null
const country_id = paisAbajoId ?? formateado.country_id ?? null;
const country = paisAbajoNombre || formateado.country || "";

return [
  {
    json: {
      id: formateado.id ?? rawRow.id ?? null,

      nombre: formateado.nombre ?? rawRow.name ?? "",

      institucion_id: formateado.institucion_id ?? null,
      institucion: formateado.institucion ?? "",

      parent_id: formateado.parent_id ?? (
        Array.isArray(rawRow.parent_id) ? rawRow.parent_id[0] : null
      ),

      parent_nombre: formateado.parent_nombre ?? (
        Array.isArray(rawRow.parent_id) ? rawRow.parent_id[1] : ""
      ),

      commercial_partner_id: formateado.commercial_partner_id ?? (
        Array.isArray(rawRow.commercial_partner_id)
          ? rawRow.commercial_partner_id[0]
          : null
      ),

      commercial_partner: formateado.commercial_partner ?? (
        Array.isArray(rawRow.commercial_partner_id)
